#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main(){
    int T; if(scanf("%d",&T)!=1) return 0; getchar(); // consume newline
    const char *ERR = "Invalid RGB color code. Must be 6 hexadecimal digits.";
    char buf[128];
    for(int tc=0; tc<T; ++tc){
        if(!fgets(buf,sizeof(buf),stdin)) break;
        // remove trailing newline
        size_t len = strlen(buf);
        while(len && (buf[len-1]=='\n' || buf[len-1]=='\r')) buf[--len]='\0';
        // left trim
        char *s = buf;
        while(*s && isspace((unsigned char)*s)) ++s;
        // right trim
        char *end = s + strlen(s) - 1;
        while(end>=s && isspace((unsigned char)*end)) *end--='\0';
        if(strlen(s)!=6){ puts(ERR); continue; }
        int ok=1;
        for(int i=0;i<6;++i){ if(!isxdigit((unsigned char)s[i])){ ok=0; break; } }
        if(!ok){ puts(ERR); }
        else{ for(int i=0;i<6;++i) putchar(toupper((unsigned char)s[i])); putchar('\n'); }
    }
    return 0;
}

