    const string ERR = "Invalid RGB color code. Must be 6 hexadecimal digits.";
    for(int tc=0; tc<T; ++tc){
        getline(cin,line);
        // trim spaces
        size_t l = line.find_first_not_of(" \t\r\n");
        size_t r = line.find_last_not_of(" \t\r\n");
        string s = (l==string::npos)?"":line.substr(l, r-l+1);
        if(s.size()!=6){ cout<<ERR<<'\n'; continue; }
        bool ok=true;
        for(char c: s) if(!isxdigit(static_cast<unsigned char>(c))){ ok=false; break; }
        if(!ok){ cout<<ERR<<'\n'; }
        else{ for(char &c: s) c = toupper(static_cast<unsigned char>(c)); cout<<s<<'\n'; }
    }
    return 0;
}

