import java.io.*;
public class Main {
    private static final String ERR = "Invalid RGB color code. Must be 6 hexadecimal digits.";
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String first = br.readLine();
        if(first==null) return;
        int T = Integer.parseInt(first.trim());
        StringBuilder out = new StringBuilder();
        for(int i=0;i<T;i++){
            String line = br.readLine();
            if(line==null) line="";
            String s = line.trim();
            if(s.length()!=6){ out.append(ERR).append('\n'); continue; }
            boolean ok=true;
            for(char c: s.toCharArray()) if(Character.digit(c,16)==-1){ ok=false; break; }
            if(!ok) out.append(ERR).append('\n');
            else out.append(s.toUpperCase()).append('\n');
        }
        System.out.print(out.toString());
    }
}

