#!/usr/bin/env python3
import sys
class InvalidRGBColorError(Exception):
    pass

def validate(code: str) -> str:
    if len(code) != 6:
        raise InvalidRGBColorError
    for ch in code:
        if ch not in "0123456789abcdefABCDEF":
            raise InvalidRGBColorError
    return code.upper()

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    T = int(data[0].strip())
    ERR = "Invalid RGB color code. Must be 6 hexadecimal digits."
    out = []
    for i in range(1, T+1):
        s = data[i].strip() if i < len(data) else ""
        try:
            out.append(validate(s))
        except InvalidRGBColorError:
            out.append(ERR)
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

